    $i = 0
    while ($i -lt $g.Length) {
        if ($i + 7 -le $g.Length -and $g.Substring($i, 7) -eq '<<ANY>>') {
            [void]$sb.Append('(?:.*/)?'); $i += 7; continue
        }
